  ('pukao-0a2fc18c-moex-00153', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '當要素市場為完全競爭時，下列何者並非成本極小化的必要條件？', '["要素的邊際技術替代率（MRTS）等於要素的相對價格", "每種要素的價格皆等於其邊際生產收益（MRP）", "各種要素的邊際生產收益（MRP）皆必須相等", "MPL/w=MPK/r，其中MPL與MPK分別代表勞動與資本的邊際產出，w與r分別代表要素價格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
